+// Fix for direct srcdoc vector: sanitize untrusted srcdoc content
+export const sanitizeSrcdoc = (unsafeContent: string): string => {
+  try {
+    const parser = new DOMParser();
+    const doc = parser.parseFromString(unsafeContent, 'text/html');
+
+    // Remove all scripts and dangerous elements
+    const dangerousTags = ['script', 'iframe', 'object', 'embed', 'form'];
+    dangerousTags.forEach(tag => {
+      doc.querySelectorAll(tag).forEach(el => el.remove());
+    });
+
+    // Strip dangerous attributes (on*, javascript:, etc.)
+    const dangerousAttrs = [/^on\w/, /java|vbscript|data:/i];
+    doc.querySelectorAll('*').forEach(el => {
+      Array.from(el.attributes).forEach(attr => {
+        if (dangerousAttrs.some(regex => regex.test(attr.name) || regex.test(attr.value))) {
+          el.removeAttribute(attr.name);
+        }
+      });
+    });
+
+    // Reconstruct srcdoc from body only
+    return `<!DOCTYPE html><html><head><meta charset="utf-8"></head><body style="margin:0;">${doc.body.innerHTML}</body></html>`;
+  } catch {
+    return ''; // fallback to empty on parse error
+  }
+};
