index 0000000..d4f8e2a
--- /dev/null
+++ b/src/sanitize-svg.js
@@ -0,0 +1,64 @@
+'use strict';
+
+const dangerousElements = new Set([
+    'script',
+    'foreignObject',
+    'animate',
+    'animateMotion',
+    'animateTransform',
+    'set'
+]);
+
+const dangerousAttributes = new Set([
+    'onload',
+    'onerror',
+    'onactivate',
+    'onbegin',
+    'onend',
+    'onclick',
+    'onfocusin',
+    'onfocusout',
+    'onrepeat',
+    'onresize',
+    'onscroll',
+    'onstart',
+    'onzoom',
+    'onmousewheel',
+    'onmousemove',
+    'onmouseout',
+    'onmouseover',
+    'onmouseup',
+    'onmousedown',
+    'onkeydown',
+    'onkeypress',
+    'onkeyup'
+]);
+
+function sanitizeNode (node) {
+    if (node.nodeType !== Node.ELEMENT_NODE) {
+        return;
+    }
+    const tagName = node.tagName.toLowerCase();
+    if (dangerousElements.has(tagName)) {
+        if (node.parentNode) {
+            node.parentNode.removeChild(node);
+        }
+        return;
+    }
+    // Strip dangerous attributes
+    for (let i = node.attributes.length; i--;) {
+        const attr = node.attributes[i];
+        if (dangerousAttributes.has(attr.name.toLowerCase())) {
+            node.removeAttribute(attr.name);
+        }
+    }
+    // Recurse
+    for (let child = node.firstChild; child; child = child.nextSibling) {
+        sanitizeNode(child);
+    }
+}
+
+function sanitizeSVG (svgString) {
+    const parser = new DOMParser();
+    const doc = parser.parseFromString(svgString, 'image/svg+xml');
+    sanitizeNode(doc.documentElement);
+    return new XMLSerializer().serializeToString(doc.documentElement);
+}
+
+module.exports = sanitizeSVG;

